library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity pixel_generator is
	generic (
		XRES	: integer := 1920;
		YRES	: integer := 1080
	);
	port (
		clk 	: in std_logic;
		resetn	: in std_logic;
		pr 		: in std_logic;
		cfg		: in std_logic;
		data 	: out std_logic_vector(15 downto 0)
	);
end pixel_generator;


architecture behavioral of pixel_generator is
	constant LEN_SINTBL		: natural := 4096;
	constant BITS_SINTBL	: natural := 13;
	type sintbl_t is array(0 to LEN_SINTBL-1) of std_logic_vector(BITS_SINTBL downto 0);
	function gen_sintbl return sintbl_t is
		use ieee.math_real.all;
		variable mem	: sintbl_t;
		variable s		: integer;
	begin
		for i in 0 to LEN_SINTBL-1 loop
			s := integer(sin(real(i) * (2.0*math_pi/real(LEN_SINTBL))) * real(2**BITS_SINTBL));
			if s >= 2**BITS_SINTBL then
				s := 2**BITS_SINTBL - 1;
			end if;
			mem(i) := std_logic_vector(to_signed(s,BITS_SINTBL+1));
		end loop;
		return mem;
	end function;
